function solve(chunks, queries) {
    // 1. Concatenate chunks to form s
    const s = chunks.join('');

    // Helper function to check if a character is valid in a word
    const isWordChar = (char) => {
        return /[a-z]/.test(char) || char === '-';
    };

    // 2. Extract all valid words from s
    const words = new Map(); // Stores word -> count

    // Iterate through s to find words
    let i = 0;
    const n = s.length;
    while (i < n) {
        // Find the start of a potential word
        if (!isWordChar(s[i])) {
            i++;
            continue;
        }

        // Start of a potential word segment
        let start = i;
        let currentWordChars = [];

        // Consume all consecutive word characters
        let j = i;
        while (j < n && isWordChar(s[j])) {
            currentWordChars.push(s[j]);
            j++;
        }
        const rawSegment = currentWordChars.join('');

        // Now, we need to validate and extract true "words" from this raw segment
        // A word cannot be a substring of a longer valid word.
        // This implies that if a segment is "abc", the words are just "abc".
        // If a segment is "a--b", the word is "a--b".
        // The rule essentially says: a word is a maximal contiguous sequence of word characters.
        // Since we've already identified a maximal contiguous sequence (rawSegment), 
        // we just need to check the internal structure for valid hyphenation.

        // The definition of a word:
        // 1. Composed of 'a'-'z' and '-'.
        // 2. '-' only if surrounded by [a-z].
        // 3. Not a substring of a longer valid word. (This is handled by maximal segmentation)

        let isValidWordSegment = true;
        for (let k = 0; k < rawSegment.length; k++) {
            const char = rawSegment[k];
            if (char === '-') {
                // Check if surrounded by letters
                const prevChar = k > 0 ? rawSegment[k - 1] : null;
                const nextChar = k < rawSegment.length - 1 ? rawSegment[k + 1] : null;

                if (!([prevChar, nextChar].every(c => c !== null && /[a-z]/.test(c)))) {
                    isValidWordSegment = false;
                    break;
                }
            } else if (!/[a-z]/.test(char)) {
                // This should not happen if the initial segment extraction was correct, 
                // but as a safeguard:
                isValidWordSegment = false;
                break;
            }
        }

        if (isValidWordSegment) {
            const word = rawSegment;
            words.set(word, (words.get(word) || 0) + 1);
        }

        // Move index i to the start of the next potential segment
        i = j;
    }

    // 3. Count occurrences for queries
    const ans = queries.map(query => {
        return words.get(query) || 0;
    });

    return ans;
}

