	"unicode"
)

func solve(chunks []string, queries []string) []int64 {
	// 1. Concatenate chunks to form s
	s := strings.Join(chunks, "")

	// Map to store word -> count
	words := make(map[string]int64)

	n := len(s)
	i := 0

	for i < n {
		char := s[i]
		if !isWordChar(char) {
			i++
			continue
		}

		// Start of a potential word segment
		start := i
		j := i

		// Consume all consecutive word characters
		for j < n && isWordChar(s[j]) {
			j++
		}
		rawSegment := s[start:j]

		// Check if the raw segment forms a valid word according to the rules
		isValidWordSegment := true
		for k := 0; k < len(rawSegment); k++ {
			char := rawSegment[k]
			if char == '-' {
				// Check if surrounded by letters
				prevChar := byte(0)
				if k > 0 {
					prevChar = rawSegment[k-1]
				}
				nextChar := byte(0)
				if k < len(rawSegment)-1 {
					nextChar = rawSegment[k+1]
				}

				isPrevLetter := k > 0 && unicode.IsLower(rune(prevChar))
				isNextLetter := k < len(rawSegment)-1 && unicode.IsLower(rune(nextChar))

				if !isPrevLetter || !isNextLetter {
					isValidWordSegment = false
					break
				}
			} else if !unicode.IsLower(rune(char)) {
				// Should not happen if isWordChar is correct, but for robustness
				isValidWordSegment = false
				break
			}
		}

		if isValidWordSegment {
			word := rawSegment
			words[word]++
		}

		// Move index i to the start of the next potential segment
		i = j
	}

	// 3. Count occurrences for queries
	ans := make([]int64, len(queries))
	for qIdx, query := range queries {
		if count, found := words[query]; found {
			ans[qIdx] = count
		} else {
			ans[qIdx] = 0
		}
	}

	return ans
}

func isWordChar(char byte) bool {
	return (char >= 'a' && char <= 'z') || char == '-'
}
