package main

// The problem requires careful interpretation of "word".
// 1. Characters allowed: 'a'-'z' and '-'.
// 2. Hyphen rule: '-' must be surrounded by [a-z].
// 3. Maximal rule: A word is not a substring of a longer valid word. This implies words are maximal contiguous sequences of valid word characters, provided they satisfy the hyphen rule internally.

func solve(chunks []string, queries []string) []int64 {
	// 1. Concatenate chunks to form s
	s := ""
	for _, chunk := range chunks {
		s += chunk
	}

	n := len(s)
	words := make(map[string]int64)

	// Helper function to check if a character is a lowercase letter
	isLetter := func(r byte) bool {
		return r >= 'a' && r <= 'z'
	}

	// Helper function to check if a character is valid within a word context
	isWordChar := func(r byte) bool {
		return isLetter(r) || r == '-'
	}

	// 2. Extract all valid words from s
	i := 0
	for i < n {
		// Skip separators
		if !isWordChar(s[i]) {
			i++
			continue
		}

		// Found the start of a potential word segment
		start := i
		j := i
		for j < n && isWordChar(s[j]) {
			j++
		}
		rawSegment := s[start:j]

		// Check if this maximal segment is a valid word according to the hyphen rule
		isValidWordSegment := true
		for k := 0; k < len(rawSegment); k++ {
			char := rawSegment[k]
			if char == '-' {
				// Check if surrounded by letters
				// Predecessor must be a letter
				prevIsLetter := k > 0 && isLetter(rawSegment[k-1])
				// Successor must be a letter
				nextIsLetter := k < len(rawSegment)-1 && isLetter(rawSegment[k+1])

				if !prevIsLetter || !nextIsLetter {
					isValidWordSegment = false
					break
				}
			} else if !isLetter(char) {
				// Should not happen based on the segment extraction, but for robustness
				isValidWordSegment = false
				break
			}
		}

		if isValidWordSegment {
			// Since we extracted the maximal contiguous sequence of word characters,
			// and verified its internal structure, this segment is a valid word.
			words[rawSegment]++
		}

		// Move to the next position after this segment
		i = j
	}

	// 3. Count occurrences for queries
